func generateRSAPrivateKey() (*rsa.PrivateKey, error) {
	//nolint:forbidigo // This is the one function allowed to generate RSA keys.
	return rsa.GenerateKey(rand.Reader, constants.RSAKeySize)
}

func httpTransport(insecure bool, pool *x509.CertPool) *http.Transport {
	// Because Teleport clients can't be configured (yet), they take the default
	// list of cipher suites from Go.
	tlsConfig := utils.TLSConfig(nil)
	tlsConfig.InsecureSkipVerify = insecure
	tlsConfig.RootCAs = pool

	return &http.Transport{
		TLSClientConfig: tlsConfig,
		Proxy: func(req *http.Request) (*url.URL, error) {
			return httpproxy.FromEnvironment().ProxyFunc()(req.URL)
		},
	}
}

func (a *Server) GetDesktopBootstrapScript(ctx context.Context) (*proto.DesktopBootstrapScriptResponse, error) {
	clusterName, err := a.GetDomainName()
	if err != nil {
		return nil, trace.Wrap(err)
	}

	certAuthority, err := a.GetCertAuthority(
		ctx,
		types.CertAuthID{Type: types.UserCA, DomainName: clusterName},
		false,
	)
	if err != nil {
		return nil, trace.Wrap(err)
	}

	if len(certAuthority.GetActiveKeys().TLS) != 1 {
		return nil, trace.BadParameter("expected one TLS key pair, got %v", len(certAuthority.GetActiveKeys().TLS))
	}

	keyPair := certAuthority.GetActiveKeys().TLS[0]
	block, _ := pem.Decode(keyPair.Cert)
	if block == nil {
		return nil, trace.BadParameter("no PEM data in CA data")
	}

	var buf bytes.Buffer
	err = DesktopAccessScriptConfigure.Execute(&buf, map[string]string{
		"caCertPEM":    string(keyPair.Cert),
		"caCertSHA1":   fmt.Sprintf("%X", sha1.Sum(block.Bytes)),
		"caCertBase64": base64.StdEncoding.EncodeToString(utils.CreateCertificateBLOB(block.Bytes)),
	})
	if err != nil {
		return nil, trace.Wrap(err)
	}

	return &proto.DesktopBootstrapScriptResponse{
		Script: buf.String(),
	}, nil
}

func (a *Server) sendValidateRequestToProxy(host string, validateRequest *authclient.ValidateTrustedClusterRequest) (*authclient.ValidateTrustedClusterResponse, error) {
	proxyAddr := url.URL{
		Scheme: "https",
		Host:   host,
	}

	opts := []roundtrip.ClientParam{
		roundtrip.SanitizerEnabled(true),
	}

	if lib.IsInsecureDevMode() {
		log.Warn("The setting insecureSkipVerify is used to communicate with proxy. Make sure you intend to run Teleport in insecure mode!")

		// Get the default transport, this allows picking up proxy from the
		// environment.
		defaultTransport, ok := http.DefaultTransport.(*http.Transport)
		if !ok {
			return nil, trace.BadParameter("invalid transport type %T", http.DefaultTransport)
		}
		// Clone the transport to not modify the global instance.
		tr := defaultTransport.Clone()
		// Disable certificate checking while in debug mode.
		tlsConfig := utils.TLSConfig(a.cipherSuites)
		tlsConfig.InsecureSkipVerify = true
		tr.TLSClientConfig = tlsConfig

		insecureWebClient := &http.Client{
			Transport: tracehttp.NewTransport(tr),
		}
		opts = append(opts, roundtrip.HTTPClient(insecureWebClient))
	}

	// We do not add the version prefix since web api endpoints will
	// contain differing version prefixes.
	clt, err := roundtrip.NewClient(proxyAddr.String(), "" /* version prefix */, opts...)
	if err != nil {
		return nil, trace.Wrap(err)
	}
	validateRequestRaw, err := validateRequest.ToRaw()
	if err != nil {
		return nil, trace.Wrap(err)
	}

	out, err := httplib.ConvertResponse(clt.PostJSON(context.TODO(), clt.Endpoint("webapi", "trustedclusters", "validate"), validateRequestRaw))
	if err != nil {
		return nil, trace.Wrap(err)
	}

	var validateResponseRaw authclient.ValidateTrustedClusterResponseRaw
	err = json.Unmarshal(out.Bytes(), &validateResponseRaw)
	if err != nil {
		return nil, trace.Wrap(err)
	}

	validateResponse, err := validateResponseRaw.ToNative()
	if err != nil {
		return nil, trace.Wrap(err)
	}

	return validateResponse, nil
}

func (a *Server) generateAndUpsertRecoveryCodes(ctx context.Context, username string) (*proto.RecoveryCodes, error) {
	codes, err := generateRecoveryCodes()
	if err != nil {
		return nil, trace.Wrap(err)
	}

	hashedCodes := make([]types.RecoveryCode, len(codes))
	for i, token := range codes {
		hashedCode, err := utils.BcryptFromPassword([]byte(token), a.bcryptCost())
		if err != nil {
			return nil, trace.Wrap(err)
		}

		hashedCodes[i].HashedCode = hashedCode
	}

	rc, err := types.NewRecoveryCodes(hashedCodes, a.GetClock().Now().UTC(), username)
	if err != nil {
		return nil, trace.Wrap(err)
	}

	if err := a.UpsertRecoveryCodes(ctx, username, rc); err != nil {
		return nil, trace.Wrap(err)
	}

	if err := a.emitter.EmitAuditEvent(a.closeCtx, &apievents.RecoveryCodeGenerate{
		Metadata: apievents.Metadata{
			Type: events.RecoveryCodeGeneratedEvent,
			Code: events.RecoveryCodesGenerateCode,
		},
		UserMetadata: authz.ClientUserMetadataWithUser(ctx, username),
	}); err != nil {
		a.logger.WarnContext(ctx, "Failed to emit recovery tokens generate event", "error", err, "user", username)
	}

	return &proto.RecoveryCodes{
		Codes:   codes,
		Created: rc.Spec.Created,
	}, nil
}

func (s *remoteSite) getRemoteClient() (authclient.ClientI, bool, error) {
	// check if all cert authorities are initiated and if everything is OK
	ca, err := s.srv.localAccessPoint.GetCertAuthority(s.ctx, types.CertAuthID{Type: types.HostCA, DomainName: s.domainName}, false)
	if err != nil {
		return nil, false, trace.Wrap(err)
	}
	if len(ca.GetTrustedTLSKeyPairs()) == 0 {
		return nil, false, trace.BadParameter("no TLS keys found")
	}
	// The fact that cluster has keys to remote CA means that the key exchange
	// has completed.

	s.logger.Debug("Using TLS client to remote cluster.")
	tlsConfig := utils.TLSConfig(s.srv.ClientTLSCipherSuites)
	// encode the name of this cluster to identify this cluster,
	// connecting to the remote one (it is used to find the right certificate
	// authority to verify)
	tlsConfig.ServerName = apiutils.EncodeClusterName(s.srv.ClusterName)
	tlsConfig.GetClientCertificate = func(*tls.CertificateRequestInfo) (*tls.Certificate, error) {
		tlsCert, err := s.srv.GetClientTLSCertificate()
		if err != nil {
			return nil, trace.Wrap(err)
		}
		return tlsCert, nil
	}
	tlsConfig.InsecureSkipVerify = true
	tlsConfig.VerifyConnection = utils.VerifyConnectionWithRoots(func() (*x509.CertPool, error) {
		pool, _, err := authclient.ClientCertPool(s.ctx, s.srv.localAccessPoint, s.domainName, types.HostCA)
		if err != nil {
			return nil, trace.Wrap(err)
		}
		return pool, nil
	})

	clt, err := authclient.NewClient(client.Config{
		Dialer: client.ContextDialerFunc(s.authServerContextDialer),
		Credentials: []client.Credentials{
			client.LoadTLS(tlsConfig),
		},
		CircuitBreakerConfig: s.srv.CircuitBreakerConfig,
	})
	if err != nil {
		return nil, false, trace.Wrap(err)
	}
	return clt, false, nil
}

func buildTLSConfig(ctx context.Context, params ConnectionConfig) (*tls.Config, bool) {
	tlsConfig := utils.TLSConfig(params.CipherSuites)
	tlsConfig.Time = params.Clock.Now
	// set NextProtos for TLS routing, the actual protocol will be h2
	tlsConfig.NextProtos = []string{string(common.ProtocolProxyGRPCInsecure), http2.NextProtoTLS}

	if params.Insecure {
		tlsConfig.InsecureSkipVerify = true
		params.Log.WarnContext(ctx, "Connecting to the cluster without validating the identity of the Proxy Server.")
	}

	// Check if proxy is behind a load balancer. If so, the connection upgrade
	// will verify the load balancer's cert using system cert pool. This
	// provides the same level of security as the client only verifies Proxy's
	// web cert against system cert pool when connection upgrade is not
	// required.
	//
	// With the ALPN connection upgrade, the tunneled TLS Routing request will
	// skip verify as the Proxy server will present its host cert which is not
	// fully verifiable at this point since the client does not have the host
	// CAs yet before completing registration.
	alpnConnUpgrade := client.IsALPNConnUpgradeRequired(ctx, params.ProxyServer, params.Insecure)
	if alpnConnUpgrade && !params.Insecure {
		tlsConfig.InsecureSkipVerify = true
		tlsConfig.VerifyConnection = verifyALPNUpgradedConn(params.Clock)
	}
	return tlsConfig, alpnConnUpgrade
}

