func insecureRegisterClient(ctx context.Context, params RegisterParams) (*authclient.Client, error) {
	const msg = "Joining cluster without validating the identity of the Auth " +
		"Server. This may open you up to a Man-In-The-Middle (MITM) attack if an " +
		"attacker can gain privileged network access. To remedy this, use the CA pin " +
		"value provided when join token was generated to validate the identity of " +
		"the Auth Server or point to a valid Certificate via the CA Path option."
	slog.WarnContext(ctx, msg)

	tlsConfig := utils.TLSConfig(params.CipherSuites)
	tlsConfig.Time = params.Clock.Now
	tlsConfig.InsecureSkipVerify = true

	client, err := authclient.NewClient(client.Config{
		Addrs: getHostAddresses(params),
		Credentials: []client.Credentials{
			client.LoadTLS(tlsConfig),
		},
		CircuitBreakerConfig: params.CircuitBreakerConfig,
		Context:              ctx,
	})
	if err != nil {
		return nil, trace.Wrap(err, "creating insecure auth client")
	}

	return client, nil
}

func pinRegisterClient(
	ctx context.Context, params RegisterParams,
) (*authclient.Client, error) {
	// Build a insecure client to the Auth Server. This is safe because even if
	// an attacker were to MITM this connection the CA pin will not match below.
	tlsConfig := utils.TLSConfig(params.CipherSuites)
	tlsConfig.InsecureSkipVerify = true
	tlsConfig.Time = params.Clock.Now
	authClient, err := authclient.NewClient(client.Config{
		Addrs: getHostAddresses(params),
		Credentials: []client.Credentials{
			client.LoadTLS(tlsConfig),
		},
		CircuitBreakerConfig: params.CircuitBreakerConfig,
		Context:              ctx,
	})
	if err != nil {
		return nil, trace.Wrap(err)
	}
	defer authClient.Close()

	// Fetch the root CA from the Auth Server. The NOP role has access to the
	// GetClusterCACert endpoint.
	localCA, err := authClient.GetClusterCACert(ctx)
	if err != nil {
		return nil, trace.Wrap(err)
	}
	certs, err := tlsca.ParseCertificatePEMs(localCA.TLSCA)
	if err != nil {
		return nil, trace.Wrap(err)
	}

	// Check that the SPKI pin matches the CA we fetched over a insecure
	// connection. This makes sure the CA fetched over a insecure connection is
	// in-fact the expected CA.
	err = utils.CheckSPKI(params.CAPins, certs)
	if err != nil {
		return nil, trace.Wrap(err)
	}

	for _, cert := range certs {
		// Check that the fetched CA is valid at the current time.
		err = utils.VerifyCertificateExpiry(cert, params.Clock)
		if err != nil {
			return nil, trace.Wrap(err)
		}

	}
	slog.InfoContext(ctx, "Joining remote cluster with CA pin.", "cluster", certs[0].Subject.CommonName)

	// Create another client, but this time with the CA provided to validate
	// that the Auth Server was issued a certificate by the same CA.
	tlsConfig = utils.TLSConfig(params.CipherSuites)
	tlsConfig.Time = params.Clock.Now
	certPool := x509.NewCertPool()
	for _, cert := range certs {
		certPool.AddCert(cert)
	}
	tlsConfig.RootCAs = certPool

	authClient, err = authclient.NewClient(client.Config{
		Addrs: getHostAddresses(params),
		Credentials: []client.Credentials{
			client.LoadTLS(tlsConfig),
		},
		CircuitBreakerConfig: params.CircuitBreakerConfig,
		Context:              ctx,
	})
	if err != nil {
		return nil, trace.Wrap(err)
	}

	return authClient, nil
}

func NewHandler(ctx context.Context, cfg Config) (*Handler, error) {
	if err := cfg.CheckAndSetDefaults(); err != nil {
		return nil, trace.Wrap(err)
	}
	logger := slog.With(teleport.ComponentKey, teleport.SchemeS3)

	opts := []func(*config.LoadOptions) error{
		config.WithRegion(cfg.Region),
	}

	if cfg.Insecure {
		opts = append(opts, config.WithHTTPClient(&http.Client{
			Transport: &http.Transport{
				TLSClientConfig: &tls.Config{InsecureSkipVerify: true},
			},
		}))
	} else {
		hc, err := defaults.HTTPClient()
		if err != nil {
			return nil, trace.Wrap(err)
		}

		opts = append(opts, config.WithHTTPClient(hc))
	}

	if cfg.CredentialsProvider != nil {
		opts = append(opts, config.WithCredentialsProvider(cfg.CredentialsProvider))
	}

	opts = append(opts, config.WithAPIOptions(awsmetrics.MetricsMiddleware()))

	resolver, err := endpoint.NewLoggingResolver(
		s3.NewDefaultEndpointResolverV2(),
		logger.With(slog.Group("service",
			"id", s3.ServiceID,
			"api_version", s3.ServiceAPIVersion,
		)),
	)
	if err != nil {
		return nil, trace.Wrap(err)
	}

	s3Opts := []func(*s3.Options){s3.WithEndpointResolverV2(resolver)}

	if cfg.Endpoint != "" {
		if _, err := url.Parse(cfg.Endpoint); err != nil {
			return nil, trace.BadParameter("configured S3 endpoint is invalid: %s", err.Error())
		}

		opts = append(opts, config.WithBaseEndpoint(cfg.Endpoint))

		s3Opts = append(s3Opts, func(options *s3.Options) {
			options.UsePathStyle = !cfg.UseVirtualStyleAddressing
		})
	}

	if modules.GetModules().IsBoringBinary() && cfg.UseFIPSEndpoint == types.ClusterAuditConfigSpecV2_FIPS_ENABLED {
		s3Opts = append(s3Opts, func(options *s3.Options) {
			options.EndpointOptions.UseFIPSEndpoint = aws.FIPSEndpointStateEnabled
		})
	}

	awsConfig, err := config.LoadDefaultConfig(context.Background(), opts...)
	if err != nil {
		return nil, trace.Wrap(err)
	}

	otelaws.AppendMiddlewares(&awsConfig.APIOptions)

	// Create S3 client with custom options
	client := s3.NewFromConfig(awsConfig, s3Opts...)

	uploader := manager.NewUploader(client)
	downloader := manager.NewDownloader(client)

	h := &Handler{
		logger:     logger,
		Config:     cfg,
		uploader:   uploader,
		downloader: downloader,
		client:     client,
	}

	start := time.Now()
	h.logger.InfoContext(ctx, "Setting up S3 bucket",
		"bucket", h.Bucket,
		"path", h.Path,
		"region", h.Region,
	)
	if err := h.ensureBucket(ctx); err != nil {
		return nil, trace.Wrap(err)
	}

	h.logger.InfoContext(ctx, "Setting up bucket S3 completed",
		"bucket", h.Bucket,
		"path", h.Path,
		"region", h.Region,
		"duration", time.Since(start),
	)
	return h, nil
}

func (h *Handler) UploadPart(ctx context.Context, upload events.StreamUpload, partNumber int64, partBody io.ReadSeeker) (*events.StreamPart, error) {
	// This upload exceeded maximum number of supported parts, error now.
	if partNumber > int64(s3manager.MaxUploadParts) {
		return nil, trace.LimitExceeded(
			"exceeded total allowed S3 limit MaxUploadParts (%d). Adjust PartSize to fit in this limit", s3manager.MaxUploadParts)
	}

	start := time.Now()
	uploadKey := h.path(upload.SessionID)
	log := h.logger.With(
		"upload", upload.ID,
		"session", upload.SessionID,
		"key", uploadKey,
	)

	// Calculate the content MD5 hash to be included in the request. This is required for S3 buckets with Object Lock enabled.
	hash := md5.New()
	if _, err := io.Copy(hash, partBody); err != nil {
		return nil, trace.Wrap(err, "failed to calculate content MD5 hash")
	}
	md5sum := base64.StdEncoding.EncodeToString(hash.Sum(nil))

	// Reset the partBody reader to the beginning before passing it the params.
	// This is necessary because after calculating the md5 hash the partBody reader will have been moved to the end of the data.
	if _, err := partBody.Seek(0, io.SeekStart); err != nil {
		return nil, trace.Wrap(err, "failed to reset part body reader to beginning")
	}

	params := &s3.UploadPartInput{
		Bucket:     aws.String(h.Bucket),
		UploadId:   aws.String(upload.ID),
		Key:        aws.String(uploadKey),
		Body:       partBody,
		PartNumber: aws.Int32(int32(partNumber)),
		ContentMD5: aws.String(md5sum),
	}

	log.DebugContext(ctx, "Uploading part", "part_number", partNumber)
	resp, err := h.client.UploadPart(ctx, params)
	if err != nil {
		return nil, trace.Wrap(awsutils.ConvertS3Error(err),
			"UploadPart(upload %v) part(%v) session(%v)", upload.ID, partNumber, upload.SessionID)
	}
	// TODO(espadolini): the AWS SDK v1 doesn't expose the Date of the response
	// in [s3.UploadPartOutput] so we use the current time instead; AWS SDK v2
	// might expose the returned Date as part of the metadata, so we should
	// check if that matches the actual LastModified of the part. It doesn't
	// make much sense to do an additional request to check the LastModified of
	// the part we just uploaded, however.
	log.InfoContext(ctx, "Uploaded part", "part_number", partNumber, "upload_curation", time.Since(start))
	return &events.StreamPart{
		ETag:         aws.ToString(resp.ETag),
		Number:       partNumber,
		LastModified: time.Now(),
	}, nil
}

func (s *Server) buildKubeClient() (kubernetes.Interface, error) {
	const idleConnsPerHost = 25

	tlsConfig := utils.TLSConfig(s.cfg.ConnTLSCipherSuites)
	tlsConfig.GetClientCertificate = func(*tls.CertificateRequestInfo) (*tls.Certificate, error) {
		tlsCert, err := s.cfg.GetConnTLSCertificate()
		if err != nil {
			return nil, trace.Wrap(err)
		}
		return tlsCert, nil
	}
	tlsConfig.InsecureSkipVerify = true
	tlsConfig.VerifyConnection = utils.VerifyConnectionWithRoots(s.cfg.GetConnTLSRoots)
	tlsConfig.ServerName = s.kubeProxySNI

	transport := utilnet.SetTransportDefaults(&http.Transport{
		TLSHandshakeTimeout: 10 * time.Second,
		TLSClientConfig:     tlsConfig,
		MaxIdleConnsPerHost: idleConnsPerHost,
		DialContext: (&net.Dialer{
			Timeout:   30 * time.Second,
			KeepAlive: 30 * time.Second,
		}).DialContext,
	})

	cfg := &rest.Config{
		Host:      s.proxyAddress,
		Transport: auth.NewImpersonatorRoundTripper(transport),
	}
	kubeClient, err := kubernetes.NewForConfig(cfg)
	return kubeClient, trace.Wrap(err)
}

func (w *WebClient) SSH(termReq web.TerminalRequest) (*terminal.Stream, error) {
	u := url.URL{
		Host:   w.i.Web,
		Scheme: client.WSS,
		Path:   fmt.Sprintf("/v1/webapi/sites/%v/connect/ws", w.tc.SiteName),
	}
	data, err := json.Marshal(termReq)
	if err != nil {
		return nil, err
	}

	q := u.Query()
	q.Set("params", string(data))
	u.RawQuery = q.Encode()

	header := http.Header{}
	header.Add("Origin", "http://localhost")
	for _, cookie := range w.cookies {
		header.Add("Cookie", cookie.String())
	}

	dialer := websocket.Dialer{
		TLSClientConfig: &tls.Config{
			InsecureSkipVerify: true,
		},
	}
	ws, resp, err := dialer.Dial(u.String(), header)
	if err != nil {
		return nil, trace.Wrap(err)
	}

	if err := makeAuthReqOverWS(ws, w.token); err != nil {
		return nil, trace.Wrap(err)
	}

	defer resp.Body.Close()
	return terminal.NewStream(context.Background(), terminal.StreamConfig{WS: ws}), nil
}

func (w *WebClient) JoinKubernetesSession(id string, mode types.SessionParticipantMode) (*terminal.Stream, error) {
	u := url.URL{
		Host:   w.i.Web,
		Scheme: client.WSS,
		Path:   fmt.Sprintf("/v1/webapi/sites/%v/kube/exec/ws", w.tc.SiteName),
	}

	params := struct {
		// Term is the initial PTY size.
		Term session.TerminalParams `json:"term"`
		// SessionID is a Teleport session ID to join as.
		SessionID session.ID `json:"sid"`
		// ParticipantMode is the mode that determines what you can do when you join an active session.
		ParticipantMode types.SessionParticipantMode `json:"mode"`
	}{
		SessionID:       session.ID(id),
		ParticipantMode: mode,
	}

	data, err := json.Marshal(params)
	if err != nil {
		return nil, err
	}

	q := u.Query()
	q.Set("params", string(data))
	u.RawQuery = q.Encode()

	header := http.Header{}
	header.Add("Origin", "http://localhost")
	for _, cookie := range w.cookies {
		header.Add("Cookie", cookie.String())
	}

	dialer := websocket.Dialer{
		TLSClientConfig: &tls.Config{
			InsecureSkipVerify: true,
		},
	}
	ws, resp, err := dialer.Dial(u.String(), header)
	if err != nil {
		return nil, trace.Wrap(err)
	}

	if err := makeAuthReqOverWS(ws, w.token); err != nil {
		return nil, trace.Wrap(err)
	}

	defer resp.Body.Close()
	return terminal.NewStream(context.Background(), terminal.StreamConfig{WS: ws}), nil
}

func CreateWebSession(proxyHost, user, password string) (*web.CreateSessionResponse, []*http.Cookie, error) {
	csReq, err := json.Marshal(web.CreateSessionReq{
		User: user,
		Pass: password,
	})
	if err != nil {
		return nil, nil, trace.Wrap(err)
	}

	// Create POST request to create session.
	u := url.URL{
		Scheme: "https",
		Host:   proxyHost,
		Path:   "/v1/webapi/sessions/web",
	}
	req, err := http.NewRequest(http.MethodPost, u.String(), bytes.NewBuffer(csReq))
	if err != nil {
		return nil, nil, trace.Wrap(err)
	}

	// Attach CSRF token in cookie and header.
	csrfToken, err := utils.CryptoRandomHex(32)
	if err != nil {
		return nil, nil, trace.Wrap(err)
	}

	req.AddCookie(&http.Cookie{
		Name:  csrf.CookieName,
		Value: csrfToken,
	})
	req.Header.Set("Content-Type", "application/json; charset=utf-8")
	req.Header.Set(csrf.HeaderName, csrfToken)

	// Issue request.
	httpClient := &http.Client{
		Transport: &http.Transport{
			TLSClientConfig: &tls.Config{
				InsecureSkipVerify: true,
			},
		},
	}
	resp, err := httpClient.Do(req)
	if err != nil {
		return nil, nil, trace.Wrap(err)
	}

	defer resp.Body.Close()
	if http.StatusOK != resp.StatusCode {
		return nil, nil, trace.ConnectionProblem(nil, "received unexpected status code: %d", resp.StatusCode)
	}

	// Read in response.
	var csResp *web.CreateSessionResponse
	err = json.NewDecoder(resp.Body).Decode(&csResp)
	if err != nil {
		return nil, nil, trace.Wrap(err)
	}

	return csResp, resp.Cookies(), nil
}

func (p *Pack) sendRequest(req *http.Request, tlsConfig *tls.Config) (int, string, error) {
	if tlsConfig == nil {
		tlsConfig = &tls.Config{
			InsecureSkipVerify: true,
		}
	}

	client := &http.Client{
		Transport: &http.Transport{
			TLSClientConfig: tlsConfig,
		},
		CheckRedirect: func(req *http.Request, via []*http.Request) error {
			return http.ErrUseLastResponse
		},
	}
	resp, err := client.Do(req)
	if err != nil {
		return 0, "", trace.Wrap(err)
	}
	defer resp.Body.Close()

	// Read in response body.
	body, err := io.ReadAll(resp.Body)
	if err != nil {
		return 0, "", trace.Wrap(err)
	}

	return resp.StatusCode, string(body), nil
}

func (p *Pack) makeWebsocketRequest(cookies []*http.Cookie, endpoint string) (string, error) {
	header := http.Header{}
	dialer := websocket.Dialer{}

	for _, c := range cookies {
		header.Add("Cookie", c.String())
	}
	dialer.TLSClientConfig = &tls.Config{
		InsecureSkipVerify: true,
	}
	conn, resp, err := dialer.Dial(fmt.Sprintf("wss://%s%s", p.rootCluster.Web, endpoint), header)
	if err != nil {
		return "", err
	}
	defer conn.Close()
	defer resp.Body.Close()
	stream := &web.WebsocketIO{Conn: conn}
	data, err := io.ReadAll(stream)
	if err != nil && websocket.IsUnexpectedCloseError(err, websocket.CloseAbnormalClosure) {
		return "", err
	}
	return string(data), nil
}

func (f *Facade) TLSConfig() (*tls.Config, error) {
	cipherSuites := utils.DefaultCipherSuites()
	if f.fips {
		cipherSuites = defaults.FIPSCipherSuites
	}

	// Build a "dynamic" tls.Config which can support a changing cert and root
	// CA pool.
	cfg := &tls.Config{
		// Set the default NextProto of "h2". Based on the value in
		// configureTLS()
		NextProtos:   []string{http2.NextProtoTLS},
		CipherSuites: cipherSuites,

		// GetClientCertificate is used instead of the static Certificates
		// field.
		Certificates: nil,
		GetClientCertificate: func(
			_ *tls.CertificateRequestInfo,
		) (*tls.Certificate, error) {
			// GetClientCertificate callback is used to allow us to dynamically
			// change the certificate when reloaded.
			f.mu.RLock()
			defer f.mu.RUnlock()
			return f.identity.TLSCert, nil
		},

		// VerifyConnection is actually used instead of the static RootCAs
		// field - however, we also populate the RootCAs field to work around
		// a lot of Teleport code which relies on this field. This means we
		// may not handle CA rotations when using certain connection
		RootCAs: f.initialIdentity.TLSCAPool,
		// InsecureSkipVerify is forced true to ensure that only our
		// VerifyConnection callback is used to verify the server's presented
		// certificate.
		InsecureSkipVerify: true,
		VerifyConnection: func(state tls.ConnectionState) error {
			// This VerifyConnection callback is based on the standard library
			// implementation of verifyServerCertificate in the `tls` package.
			// We provide our own implementation so we can dynamically handle
			// a changing CA Roots pool.
			if f.insecure {
				return nil
			}
			caPool := func() *x509.CertPool {
				f.mu.RLock()
				defer f.mu.RUnlock()
				return f.identity.TLSCAPool
			}()
			opts := x509.VerifyOptions{
				DNSName: state.ServerName,
				Roots:   caPool,
			}
			if len(state.PeerCertificates) > 1 {
				opts.Intermediates = x509.NewCertPool()
				for _, cert := range state.PeerCertificates[1:] {
					// Whilst we don't currently use intermediate certs at
					// Teleport, including this here means that we are
					// future-proofed in case we do.
					opts.Intermediates.AddCert(cert)
				}
			}
			_, err := state.PeerCertificates[0].Verify(opts)
			return err
		},
		ServerName: apiutils.EncodeClusterName(f.initialIdentity.ClusterName),
	}

	return cfg, nil
}

func (c *kubeletClient) httpClient() (url.URL, *http.Client, error) {
	host := c.getEnv(nodeNameEnv)

	if c.cfg.ReadOnlyPort != 0 {
		return url.URL{
			Scheme: "http",
			Host:   net.JoinHostPort(host, strconv.Itoa(c.cfg.ReadOnlyPort)),
		}, &http.Client{}, nil
	}

	port := cmp.Or(c.cfg.SecurePort, defaultSecurePort)

	transport := &http.Transport{
		TLSClientConfig: &tls.Config{},
	}

	switch {
	case c.cfg.SkipVerify:
		transport.TLSClientConfig.InsecureSkipVerify = true
	default:
		caPath := cmp.Or(c.cfg.CAPath, defaultCAPath)
		certPool := x509.NewCertPool()
		caPEM, err := os.ReadFile(caPath)
		if err != nil {
			return url.URL{}, nil, trace.Wrap(err, "reading CA file %q", caPath)
		}
		if !certPool.AppendCertsFromPEM(caPEM) {
			return url.URL{}, nil, trace.BadParameter("failed to append CA cert from %q", caPath)
		}
		transport.TLSClientConfig.RootCAs = certPool
	}

	client := &http.Client{
		Transport: transport,
		// 10 seconds is fairly generous given that we're expecting to talk to
		// kubelet on the same physical machine.
		Timeout: 10 * time.Second,
	}

	switch {
	case c.cfg.Anonymous:
	// Nothing to do
	case c.cfg.TokenPath != "":
		fallthrough
	default:
		tokenPath := cmp.Or(c.cfg.TokenPath, defaultServiceAccountTokenPath)
		token, err := os.ReadFile(tokenPath)
		if err != nil {
			return url.URL{}, nil, trace.Wrap(err, "reading token file %q", tokenPath)
		}
		client.Transport = roundTripperFn(func(req *http.Request) (*http.Response, error) {
			req.Header.Set("Authorization", fmt.Sprintf("Bearer %s", token))
			return transport.RoundTrip(req)
		})
	}

	return url.URL{
		Scheme: "https",
		Host:   net.JoinHostPort(host, strconv.Itoa(port)),
	}, client, nil
}

func (p *PluginsCommand) InstallSCIM(ctx context.Context, args installPluginArgs) error {
	log := p.config.Logger.With(logFieldPlugin, p.install.name)

	log.DebugContext(ctx, "Fetching cluster info...")
	info, err := args.authClient.Ping(ctx)
	if err != nil {
		return trace.Wrap(err, "failed fetching cluster info")
	}

	scimBaseURL := fmt.Sprintf("https://%s/v1/webapi/scim/%s", info.ProxyPublicAddr, p.install.name)

	scimTokenHash, err := bcrypt.GenerateFromPassword([]byte(p.install.scim.token), bcrypt.DefaultCost)
	if err != nil {
		return trace.Wrap(err)
	}

	connectorID := p.install.scim.samlConnector
	log.DebugContext(ctx, "Validating SAML Connector...", logFieldSAMLConnector, connectorID)
	connector, err := args.authClient.GetSAMLConnector(ctx, p.install.scim.samlConnector, false)
	if err != nil {
		if !p.install.scim.force {
			return trace.Wrap(err, "failed validating SAML connector")
		}
	}

	role := p.install.scim.role
	log.DebugContext(ctx, "Validating Default Role...", logFieldRole, role)
	if _, err := args.authClient.GetRole(ctx, role); err != nil {
		if !p.install.scim.force {
			return trace.Wrap(err, "failed validating role")
		}
	}

	request := &pluginsv1.CreatePluginRequest{
		Plugin: &types.PluginV1{
			SubKind: types.PluginSubkindProvisioning,
			Metadata: types.Metadata{
				Labels: map[string]string{
					types.HostedPluginLabel: "true",
					types.SCIMBaseURLLabel:  scimBaseURL,
				},
				Name: p.install.name,
			},
			Spec: types.PluginSpecV1{
				Settings: &types.PluginSpecV1_Scim{
					Scim: &types.PluginSCIMSettings{
						SamlConnectorName: p.install.scim.samlConnector,
						DefaultRole:       p.install.scim.role,
					},
				},
			},
		},
		StaticCredentials: &types.PluginStaticCredentialsV1{
			ResourceHeader: types.ResourceHeader{
				Metadata: types.Metadata{
					Name: p.install.name,
				},
			},
			Spec: &types.PluginStaticCredentialsSpecV1{
				Credentials: &types.PluginStaticCredentialsSpecV1_APIToken{
					APIToken: string(scimTokenHash),
				},
			},
		},
	}

	log.DebugContext(ctx, "Creating SCIM Plugin...")
	if _, err := args.plugins.CreatePlugin(ctx, request); err != nil {
		log.ErrorContext(ctx, "Failed to create SCIM integration", logErrorMessage(err))
		return trace.Wrap(err)
	}

	fmt.Printf("Successfully created SCIM plugin %q\n", p.install.name)
	fmt.Printf("SCIM base URL: %s\n", scimBaseURL)

	if connector == nil {
		return nil
	}

	switch connector.Origin() {
	case types.OriginOkta:
		fmt.Println("Follow this guide to configure SCIM provisioning on Okta side: https://goteleport.com/docs/application-access/okta/hosted-guide/#configuring-scim-provisioning")
	}
	return nil
}

func generateCredentials(pluginName string, oktaSettings oktaArgs) ([]*types.PluginStaticCredentialsV1, error) {
	var creds []*types.PluginStaticCredentialsV1
	if oktaSettings.apiToken != "" {
		label := types.OktaCredPurposeAuth
		if !oktaSettings.appGroupSync {
			label = types.CredPurposeOKTAAPITokenWithSCIMOnlyIntegration
		}

		oktaAPICreds := &types.PluginStaticCredentialsV1{
			ResourceHeader: types.ResourceHeader{
				Metadata: types.Metadata{
					Name: pluginName,
					Labels: map[string]string{
						types.OktaCredPurposeLabel: label,
					},
				},
			},
			Spec: &types.PluginStaticCredentialsSpecV1{
				Credentials: &types.PluginStaticCredentialsSpecV1_APIToken{
					APIToken: oktaSettings.apiToken,
				},
			},
		}
		creds = append(creds, oktaAPICreds)
	}

	if oktaSettings.scimToken != "" {
		scimTokenHash, err := bcrypt.GenerateFromPassword([]byte(oktaSettings.scimToken), bcrypt.DefaultCost)
		if err != nil {
			return nil, trace.Wrap(err)
		}
		oktaSCIMCreds := &types.PluginStaticCredentialsV1{
			ResourceHeader: types.ResourceHeader{
				Metadata: types.Metadata{
					Name: pluginName + "-scim-token",
					Labels: map[string]string{
						types.OktaCredPurposeLabel: types.OktaCredPurposeSCIMToken,
					},
				},
			},
			Spec: &types.PluginStaticCredentialsSpecV1{
				Credentials: &types.PluginStaticCredentialsSpecV1_APIToken{
					APIToken: string(scimTokenHash),
				},
			},
		}
		creds = append(creds, oktaSCIMCreds)
	}
	return creds, nil
}
